const body = $input.first().json.body;
try {
  const message = body.entry?.[0]?.changes?.[0]?.value?.messages?.[0];
  if (!message) return [{ json: { skip: true } }];
  const meta = body.entry[0].changes[0].value.metadata;
  const from = message.from;
  const type = message.type;
  const phoneNumberId = meta.phone_number_id;
  const waMessageId = message.id || null;
  const replyTo = message.context?.id || null;
  const waTimestamp = message.timestamp || null;
  let textContent = '';
  let mediaId = null;
  let mediaType = 'text';   // ruta del switch: 'audio' | 'image' | 'text'
  let msgType = 'text';     // tipo guardado en BD: 'image' | 'text'
  if (type === 'text') {
    textContent = message.text.body;
  } else if (type === 'audio' || type === 'voice') {
    mediaId = message.audio?.id || message.voice?.id;
    mediaType = 'audio';
  } else if (type === 'image') {
    mediaId = message.image.id;
    textContent = message.image.caption || '[imagen]';
    mediaType = 'image';
    msgType = 'image';
  } else {
    textContent = '[Archivo no soportado]';
  }
  const RESET_KEYWORDS = ['nuevo chat', 'nueva sesion', 'nueva sesión', 'reiniciar'];
  const normalized = textContent.toLowerCase().trim().replace(/[¡!¿?.,]/g, '');
  const isReset = type === 'text' && RESET_KEYWORDS.some(k => normalized === k || normalized.includes(k));
  const finalText = isReset ? 'Quiero iniciar una nueva sesión' : textContent;
  return [{ json: { from, type, textContent: finalText, mediaId, mediaType, msgType, waMessageId, replyTo, waTimestamp, phoneNumberId, skip: false, isReset } }];
} catch (err) {
  return [{ json: { skip: true } }];
}

const inputData = $input.first().json;
const baseData = $('Parsear Mensaje WA').first().json;

// Audio llega con .text (respuesta de Groq Whisper)
// Texto llega con .textContent ya seteado
const textContent = inputData.text || inputData.textContent || '';

return [{ json: { ...baseData, textContent } }];

// Obtener conteo de mensajes hoy (desde nodo anterior)
const countHeaders = $('Contar Mensajes Hoy').first().json.headers || {};
const contentRange = countHeaders['content-range'] || '';
const match = contentRange.match(/\/(\d+)$/);
const count = match ? parseInt(match[1]) : 0;

// Leer límite dinámico desde Supabase settings
let dailyLimit = 10;
try {
  const limitRows = $input.all();
  if (limitRows.length > 0 && limitRows[0].json && limitRows[0].json.value) {
    dailyLimit = parseInt(limitRows[0].json.value) || 10;
  }
} catch(e) { /* usar default 10 */ }

// Datos del mensaje según la rama que corrió: imagen, audio o texto
let msgData;
try {
  msgData = $('Preparar Imagen').first().json;
} catch(e1) {
  try {
    msgData = $('Unificar Transcripción').first().json;
  } catch(e2) {
    msgData = $('Parsear Mensaje WA').first().json;
  }
}

return [{ json: { ...msgData, mensajesHoy: count, limitAlcanzado: count >= dailyLimit, dailyLimit } }];

