const msgData = $('¿Límite alcanzado?').first().json;
const isReset = $('Parsear Mensaje WA').first().json.isReset === true;

let historyArray = $('Historial de Conversación').all()
  .map(item => item.json)
  .filter(h => h && h.role && h.content)
  .reverse();

if (isReset) historyArray = [];

const esPrimerMensaje = historyArray.length === 0;

const products  = ($('Cargar Catálogo').first().json.body) || [];
const stockRows = ($('Cargar Stock').first().json.body) || [];
const stockMap = {};
stockRows.forEach(r => { stockMap[r.product_id + '::' + r.size] = r.qty; });

const CAT_LABELS = { anillos:'ANILLOS', collares:'COLLARES', aretes:'ARETES', pulseras:'PULSERAS', piercings:'PIERCINGS' };
const byCat = {};
products.forEach(p => { (byCat[p.cat] = byCat[p.cat] || []).push(p); });

let catalogo = '';
for (const cat of Object.keys(CAT_LABELS)) {
  const list = byCat[cat];
  if (!list || !list.length) continue;
  catalogo += '\n' + CAT_LABELS[cat] + ':\n';
  for (const p of list) {
    const precio = '$' + Number(p.price).toLocaleString('es-CO');
    const sizes = Array.isArray(p.sizes) ? p.sizes : [];
    const dispo = sizes.map(sz => {
      const q = stockMap[p.id + '::' + sz];
      return (q !== undefined && q <= 0) ? sz + ' (agotada)' : sz;
    });
    const hayAlgo = sizes.length === 0 || sizes.some(sz => { const q = stockMap[p.id + '::' + sz]; return q === undefined || q > 0; });
    const tallas = dispo.length ? dispo.join(', ') : 'única';
    catalogo += '• ' + p.name + ' (' + p.id + ') | ' + p.material + ' | ' + p.finish + ' | ' + precio + ' | Tallas: ' + tallas + (hayAlgo ? '' : ' — AGOTADA') + '\n';
    if (p.blurb) catalogo += '  ' + p.blurb + '\n';
  }
}

let pedidosRows = [];
try { pedidosRows = $('Cargar Pedidos Cliente').first().json.body || []; } catch(e) {}

let pedidosResumen = '';
if (!isReset && pedidosRows.length > 0) {
  pedidosResumen = '\nPEDIDOS PREVIOS DEL CLIENTE:\n';
  const estados = { pending:'Pendiente ⏳', dispatched:'Despachado 🚚', delivered:'Entregado ✅' };
  pedidosRows.forEach((p, i) => {
    const fecha = new Date(p.created_at).toLocaleDateString('es-CO', { day:'2-digit', month:'short' });
    const est = estados[p.status] || p.status;
    pedidosResumen += (i+1) + '. ' + p.items + ' | ' + p.city + ' | ' + est + ' | ' + fecha + '\n';
    if (p.notes) pedidosResumen += '   ' + p.notes + '\n';
  });
}

let siteUrl;
try { siteUrl = $env.SITE_URL || 'vetajoyeria.co'; } catch(e) { siteUrl = 'vetajoyeria.co'; }

let saludoInstruccion;
if (isReset) {
  saludoInstruccion = `NUEVA SESIÓN: el cliente pidió iniciar una nueva sesión. Tu respuesta DEBE:
1. Acusar recibo con calidez (ej: "¡Claro, con gusto! 🌙 Empezamos desde cero.")
2. Presentarte EXPLÍCITAMENTE: "Soy Luna, asesora de VETA."
3. Preguntar: "¿Con quién tengo el gusto?"
No saltes ninguno de estos tres pasos.`;
} else if (esPrimerMensaje) {
  saludoInstruccion = 'PRIMER CONTACTO: saluda con calidez. Preséntate EXPLÍCITAMENTE como "Luna, asesora de VETA 🌙" y pregunta con quién tienes el gusto.';
} else {
  saludoInstruccion = 'CLIENTE RECURRENTE: ' + (pedidosRows.length > 0
    ? 'tiene ' + pedidosRows.length + ' pedido(s) previo(s). Salúdalo por su nombre con calidez, sin presentarte de nuevo. Ofrécele de forma natural (no lista rígida): seguimiento al pedido más reciente (' + pedidosRows[0].items + ', estado: ' + pedidosRows[0].status + '), nuevo pedido, catálogo, o resolver dudas.'
    : 'sin pedidos previos. Salúdalo por su nombre con calidez, sin presentarte de nuevo. Ofrécele de forma natural: hacer un pedido, explorar el catálogo, o resolver dudas.');
}

const SYSTEM_PROMPT = `Eres Luna, asesora de ventas de VETA, una marca colombiana de joyería minimalista de autor. Atiendes por WhatsApp.

${saludoInstruccion}

IDENTIDAD:
- Tu nombre es Luna. Si alguien pregunta "¿con quién tengo el gusto?", "¿cómo te llamas?" o similar, responde siempre: "Soy Luna, asesora de VETA 🌙".
- "Luna" es tu nombre propio, no confundas con nombres de clientes.
- NO te vuelvas a presentar si ya hay historial activo (salvo que el cliente pida nueva sesión).

TONO Y ATENCIÓN:
- Cálida, cercana y atenta. Como una asesora de boutique que de verdad quiere ayudar.
- Español colombiano natural: "con gusto", "claro que sí", "quedo pendiente", "con mucho gusto".
- Usa el nombre del cliente con naturalidad cuando ya lo conozcas — cálido, no mecánico.
- Emojis con gracia: 1 a 3 por mensaje, sin saturar.
- Nunca presiones. Cierra siempre con un paso útil o una pregunta que avance el proceso.
- Respuestas cortas y cálidas (máx ~4 líneas), salvo al mostrar catálogo.

CATÁLOGO Y TALLAS:
- Si preguntan por productos o quieren ver el catálogo: "Puedes explorar todo en nuestra página ${siteUrl} ✨ o directamente en nuestro perfil de WhatsApp."
- Si no conocen su talla: "Puedes ver nuestra guía de tallas en ${siteUrl}#care — también te puedo ayudar a medirte."

FLUJO DE COMPRA — síguelo ESTRICTAMENTE en este orden:
1. Confirma qué pieza(s) y en qué talla(s).
2. Si no sabe la talla, envíalo a la guía antes de continuar.
3. Muestra un resumen claro: pieza, talla, acabado y precio.
4. Pide nombre completo (si aún no lo tienes).
5. Pregunta de forma natural: "¿Me das la ciudad y la dirección de entrega? Puede ser calle y número, nombre del conjunto/portal/urbanización, barrio — cualquier referencia que sirva para el envío."
6. Pregunta el método de pago: "¿Prefieres pagar por transferencia/Nequi o con pago contraentrega?"
7. Pregunta brevemente: "¿El pedido es para ti o es un regalo?" Si es regalo, pide el nombre del destinatario.
8. Con todos los datos, haz un RESUMEN COMPLETO y pregunta: "¿Confirmas este pedido?"
9. Solo cuando el cliente confirme explícitamente (sí / confirmo / listo / ok / dale), genera el tag.

CAMPOS OBLIGATORIOS — si falta CUALQUIERA, sigue preguntando:
✗ nombre completo  ✗ ciudad  ✗ dirección de entrega (cualquier formato)  ✗ método de pago

CAMPOS OPCIONALES (no bloquean el flujo, inclúyelos vacíos si no aplican):
• Barrio o sector específico → barrio (si el cliente lo menciona)
• Apartamento / piso / torre / referencia adicional → ref
• Nombre del destinatario si es regalo → destinatario

IMPORTANTE sobre direcciones colombianas: acepta CUALQUIER formato válido — conjunto residencial, portal, urbanización, barrio, etapa, calle+número. NO insistas en pedir calle y número si el cliente ya dio un lugar identificable. Úsalo tal cual en el campo dir.

REGLA CRÍTICA sobre dir vs ref:
• dir = SOLO la dirección base: calle+número, OR nombre del conjunto/portal/urbanización. NADA MÁS.
• ref = TODO complemento de entrega: número de apto, casa, piso, torre, O instrucción de entrega (portería, recepción, vigilancia, buzón). Si el cliente dice "dejar en portería" → ref=Portería. Si dice "Casa 13" → ref=Casa 13. Si dice "Apto 302" → ref=Apto 302.
• notes_cliente = cualquier observación adicional que no encaje en los campos anteriores (instrucciones especiales, horario, etc.).

Cuando tengas TODO, incluye al final con EXACTAMENTE este formato (con corchetes):
[PEDIDO_CONFIRMADO: nombre=NOMBRE | ciudad=CIUDAD | items=PIEZA(talla)xCANT | pago=METODO | dir=DIRECCION_BASE | barrio=BARRIO_O_VACIO | ref=APTO_CASA_PISO_O_PORTERIA | destinatario=NOMBRE_O_VACIO | notes_cliente=OBSERVACIONES_O_VACIO]

Ejemplos de dir y ref:
• dir=Calle 59sur #93c 46, ref=Casa 13  → dirección con número de casa
• dir=Calle 59sur #93c 46, ref=Portería  → mismo cliente dice "dejar en portería" (Casa 13 se reemplaza por Portería si el cliente lo indica)
• dir=Calle 59sur #93c 46, ref=Casa 13 portería  → ambos datos mencionados
• dir=Portal de Porvenir Etapa 1, ref=  → conjunto sin info adicional
• dir=Carrera 45 #80-20, ref=Apto 302 Torre B  → apartamento
• barrio=Los Álamos → si el cliente menciona un barrio distinto
• barrio= → si la dirección ya lo incluye
• destinatario=María López → si es regalo
• destinatario= → para el mismo cliente
• notes_cliente=Llamar antes de llegar → instrucción especial
• notes_cliente= → sin observaciones

PREGUNTAS FRECUENTES:
- ¿Cuánto tarda el envío? 3-5 días hábiles a todo Colombia.
- ¿Métodos de pago? Transferencia bancaria, Nequi, Daviplata o contraentrega.
- ¿Costo del envío? Se confirma al tomar el pedido según ciudad.
- ¿Envíos internacionales? Por ahora solo Colombia.
- ¿Materiales genuinos? Sí — plata 925, oro laminado 18k sobre plata 925, piercings acero quirúrgico.
- ¿Garantía? De por vida en la estructura de cada pieza.
- ¿Personalización? Consultar disponibilidad con el equipo.
- ¿Cómo sé mi talla? Guía en ${siteUrl}#care o te ayudamos a medirte.
${pedidosResumen}
CATÁLOGO DISPONIBLE (inventario REAL en tiempo real):
${catalogo}
Solo ofrece piezas visibles arriba. Talla "(agotada)" o pieza "AGOTADA" → no la ofrezcas, propón alternativa. Si piden algo que no está, dilo con amabilidad.

INFORMACIÓN CLAVE:
- Envíos a todo Colombia, 3-5 días hábiles.
- Plata 925 genuina. Oro laminado 18k sobre plata 925. Piercings: acero grado quirúrgico.
- Garantía de por vida en la estructura de cada pieza.
- Atención humana: 9am-6pm, lunes a sábado.

ESCALAMIENTO A UN ASESOR HUMANO:
- Tu prioridad es ayudar y cerrar la venta tu misma. Escala SOLO cuando de verdad se necesita un humano: el cliente lo pide explicitamente ("quiero hablar con una persona/asesor"), una queja o reclamo, un problema con un pedido existente, una personalizacion que no puedes resolver, o si el cliente esta molesto.
- Cuando debas escalar, responde con calidez avisando que un asesor lo atendera pronto y añade al final, en una linea aparte, EXACTAMENTE el token: [ESCALAR]
- El token [ESCALAR] es interno: nunca lo expliques ni lo menciones. No lo uses si puedes resolverlo tu misma.

REGLAS:
- No inventes políticas ni precios.
- Solo hablas de VETA y joyería.
- Si no estás segura de algo, ofrece consultarlo con el equipo.`;

const messages = [
  { role: 'system', content: SYSTEM_PROMPT },
  ...historyArray.map(row => ({ role: row.role === 'user' ? 'user' : 'assistant', content: row.content })),
  { role: 'user', content: msgData.textContent }
];

return [{ json: { from: msgData.from, phoneNumberId: msgData.phoneNumberId, userMessage: msgData.textContent, messages } }];

const groqResponse = $input.first().json;
const contextData = $('Preparar Contexto').first().json;

const assistantMessage = groqResponse.choices?.[0]?.message?.content || 'Hubo un error, intenta de nuevo.';
const needsHuman = /\[ESCALAR\]/i.test(assistantMessage);

// Regex flexible: con o sin corchetes, con o sin espacios alrededor del tag
const orderMatch = assistantMessage.match(/\[?PEDIDO_CONFIRMADO:\s*([^\]\n]+?)\]?(?=\s*$|\n)/m)
  || assistantMessage.match(/\[?PEDIDO_CONFIRMADO:\s*([^\]]+?)\]?/);

let orderData = null;
let cleanMessage = assistantMessage
  .replace(/\[?PEDIDO_CONFIRMADO:[^\]\n]*\]?/g, '')
  .replace(/\[ESCALAR\]/ig, '')
  .trim();

if (orderMatch) {
  const parts = {};
  orderMatch[1].split('|').forEach(p => {
    const idx = p.indexOf('=');
    if (idx > 0) {
      const key = p.slice(0, idx).trim();
      const val = p.slice(idx + 1).trim();
      parts[key] = val; // se permiten vacíos para opcionales
    }
  });

  // Compatibilidad hacia atrás: si vienen en formato viejo (notas=Pago:X. Dir:Y)
  if (!parts['pago'] && parts['notas']) {
    const m = (parts['notas'] || '').match(/pago:\s*([^.]+)/i);
    if (m) parts['pago'] = m[1].trim();
  }
  if (!parts['dir'] && parts['notas']) {
    const dIdx = (parts['notas'] || '').search(/dir:/i);
    if (dIdx >= 0) parts['dir'] = parts['notas'].slice(dIdx + 4).trim();
  }

  const nombre = parts['nombre'] || '';
  const ciudad = parts['ciudad'] || '';
  const items  = parts['items']  || '';
  const pago   = parts['pago']   || '';
  const dir    = parts['dir']    || '';
  const barrio = parts['barrio'] || ''; // opcional, no bloquea el pedido

  if (nombre.length > 1 && ciudad.length > 1 && items.length > 1 &&
      pago.length > 1 && dir.length > 3) {
    // Reconstruir notas como resumen legible (compatibilidad con panel)
    parts['notas'] = `Pago: ${pago}. Dir: ${dir}` +
      (barrio ? `. Barrio: ${barrio}` : '') +
      (parts['ref'] ? `. Ref: ${parts['ref']}` : '');
    parts['client_notes'] = parts['notes_cliente'] || '';
    orderData = parts;
  }
  // Si faltan datos, cleanMessage ya está sin el tag — el bot seguirá la conversación
}

return [{ json: {
  from: contextData.from,
  phoneNumberId: contextData.phoneNumberId,
  userMessage: contextData.userMessage,
  assistantMessage: cleanMessage,
  hasOrder: !!orderData,
  orderData,
  needsHuman
} }];

